    "# Installing packages\n",
    "\n",
    "packages <- c(\n",
    "  \"stm\", \"tidytext\", \"dplyr\", \"ggplot2\", \"readr\",\n",
    "  \"stringr\", \"tidyr\", \"scales\", \"RColorBrewer\", \"gridExtra\"\n",
    ")\n",
    "\n",
    "installed <- rownames(installed.packages())\n",
    "\n",
    "for (p in packages) {\n",
    "  if (!(p %in% installed)) {\n",
    "    install.packages(p, repos = \"https://cran.r-project.org\")\n",
    "  }\n",
    "}\n",
    "\n",
    "# Load libraries\n",
    "library(stm)\n",
    "library(tidytext)\n",
    "library(dplyr)\n",
    "library(ggplot2)\n",
    "library(readr)\n",
    "library(stringr)\n",
    "library(tidyr)\n",
    "library(scales)\n",
    "library(RColorBrewer)\n",
    "library(gridExtra)\n",
    "library(readr)\n",
    "\n",
    "cat(\"Packages ready.\\n\")"
   ]
  },
