   "source": [
    "# STEP 1: Set File Paths\n",
    "\n",
    "# This section tells R where to find the outputs generated from the Python notebook.\n",
    "# These outputs are chained from the python NOTEBOOK\n",
    "\n",
    "# Example dataset path:\n",
    "# /kaggle/input/rai-project/\n",
    "#\n",
    "# Define:\n",
    "# - PYTHON_OUTPUT → root folder of uploaded dataset\n",
    "# - TEXT_FOLDER   → folder containing one cleaned text file per document\n",
    "# - METADATA_PATH → CSV with document-level metadata\n",
    "# - OUTPUT_PATH   → where new results from this notebook will be saved\n",
    "\n",
    "PYTHON_OUTPUT <- \"/kaggle/input/notebooks/amakapeace/rai-project/\"\n",
    "TEXT_FOLDER   <- file.path(PYTHON_OUTPUT, \"clean_texts\")\n",
    "METADATA_PATH <- file.path(PYTHON_OUTPUT, \"corpus_metadata.csv\")\n",
    "OUTPUT_PATH   <- \"/kaggle/working/\"\n",
    "\n",
    "# Check that the metadata file exists.\n",
    "# If this fails, it usually means the dataset name or path is incorrect.\n",
    "\n",
    "if (!file.exists(METADATA_PATH)) {\n",
    "  stop(paste(\n",
    "    \"Metadata file not found at:\", METADATA_PATH,\n",
    "    \"\\nMake sure the Python outputs were uploaded correctly.\"\n",
    "  ))\n",
    "}\n",
    "\n",
    "# Check that the cleaned text folder exists.\n",
    "# This folder should contain files like doc_000.txt, doc_001.txt, etc.\n",
    "\n",
    "if (!dir.exists(TEXT_FOLDER)) {\n",
    "  stop(paste(\n",
    "    \"Text folder not found at:\", TEXT_FOLDER,\n",
    "    \"\\nExpected a 'clean_texts/' folder inside the dataset.\"\n",
    "  ))\n",
    "}\n",
    "\n",
    "# Print paths so you can visually confirm everything is correct before proceeding.\n",
    "\n",
    "cat(\"Paths loaded successfully.\\n\\n\")\n",
    "\n",
    "cat(\"Metadata file:\\n\")\n",
    "print(METADATA_PATH)\n",
    "\n",
    "cat(\"\\nSample text files:\\n\")\n",
    "print(head(list.files(TEXT_FOLDER)))"
   ]
  },
