   "source": [
    "# Step 2: Load Metadata and read text files\n",
    "\n",
    "# This step brings together:\n",
    "# - document-level metadata (company, year, doc_type, etc.)\n",
    "# - the cleaned text files generated in the Python pipeline\n",
    "#\n",
    "# Each row in metadata is matched to a corresponding text file:\n",
    "#   doc_000.txt → first document\n",
    "#   doc_001.txt → second document, etc.\n",
    "#\n",
    "# The goal is to build a dataset where each document has:\n",
    "#   (a) metadata\n",
    "#   (b) its full cleaned text\n",
    "# This is required for STM, which uses both text and covariates.\n",
    "\n",
    "\n",
    "# Load metadata\n",
    "\n",
    "\n",
    "metadata <- read_csv(METADATA_PATH, show_col_types = FALSE)\n",
    "\n",
    "cat(paste(\"Loaded metadata for\", nrow(metadata), \"documents\\n\"))\n",
    "\n",
    "# Quick distribution checks to confirm balance across key variables\n",
    "cat(\"By company:\\n\"); print(table(metadata$company))\n",
    "cat(\"By document type:\\n\"); print(table(metadata$doc_type))\n",
    "\n",
    "\n",
    "\n",
    "# Read cleaned text files\n",
    "\n",
    "# Initialize empty character vector to store document texts\n",
    "texts <- character(nrow(metadata))\n",
    "\n",
    "for (i in 1:nrow(metadata)) {\n",
    "\n",
    "  # File naming follows Python pipeline style: doc_000.txt, doc_001.txt, ...\n",
    "  txt_file <- file.path(TEXT_FOLDER, sprintf(\"doc_%03d.txt\", i - 1))\n",
    "\n",
    "  if (file.exists(txt_file)) {\n",
    "\n",
    "    # Read entire file and collapse into a single string\n",
    "    texts[i] <- paste(readLines(txt_file, warn = FALSE), collapse = \" \")\n",
    "\n",
    "  } else {\n",
    "\n",
    "    # If a file is missing, store empty string and flag it\n",
    "    texts[i] <- \"\"\n",
    "    cat(paste(\"WARNING: file not found:\", txt_file, \"\\n\"))\n",
    "  }\n",
    "}\n",
    "\n",
    "\n",
    "\n",
    "# Attach text to metadata\n",
    "\n",
    "metadata$text <- texts\n",
    "\n",
    "# Remove documents with extremely short or empty text\n",
    "# These can break STM or introduce noise\n",
    "\n",
    "# Keep all documents for now\n",
    "# STM will handle filtering later if needed\n",
    "\n",
    "texts <- metadata$text\n",
    "\n",
    "cat(paste(\"\\nSuccessfully loaded\", length(texts), \"documents\\n\"))"
   ]
  },
