   "source": [
    "# Before preprocessing, I am taking a step back to inspect the most frequent and widely occurring terms in the corpus. The goal here is not to remove\n",
    "# words simply because they are common, but to understand which terms are helping the analysis and which are just background noise.\n",
    "#\n",
    "# In a corpus like this, some words (e.g., \"ai\", \"model\", company names) appear in nearly every document because they reflect the shared context\n",
    "# of Responsible AI reporting, not meaningful differences between documents.\n",
    "#\n",
    "# So, I will use this inspection to guide the construction of domain-specific stopwords,\n",
    "# removing only those terms that are ubiquitous and non-discriminative, while\n",
    "# retaining frequent but substantively important words (e.g., \"risk\", \"fairness\",\n",
    "# \"privacy\") that are central to the themes I want the model to uncover.\n",
    "\n",
    "# Inspect high-frequency terms before finalizing corpus-specific stopwords\n",
    "\n",
    "freq_df <- metadata %>%\n",
    "  select(filename, text) %>%\n",
    "  unnest_tokens(word, text) %>%\n",
    "  count(word, sort = TRUE)\n",
    "\n",
    "head(freq_df, 50)"
   ]
  },
