   "source": [
    "# Inspect document frequency\n",
    "# This shows how many documents each term appears in\n",
    "# Doing this because a word that appears in many documents is more likely to be background \n",
    "# vocabulary than a word that appears many times in just a few documents:\n",
    "\n",
    "doc_freq <- metadata %>%\n",
    "  select(filename, text) |>\n",
    "  unnest_tokens(word, text) |>\n",
    "  distinct(filename, word) %>%\n",
    "  count(word, sort = TRUE)\n",
    "\n",
    "head(doc_freq, 50)"
   ]
  },
