   "source": [
    "# STEP 3: PREPROCESS TEXT FOR STM\n",
    "#\n",
    "# This step prepares the corpus for topic modeling.\n",
    "# textProcessor() applies standard preprocessing:\n",
    "# - converts text to lowercase\n",
    "# - removes punctuation and numbers\n",
    "# - removes standard stopwords\n",
    "# - applies stemming\n",
    "#\n",
    "# The goal here is not aggressive cleaning, but selective reduction:\n",
    "# to remove background noise while preserving terms that structure\n",
    "# meaningful variation across documents.\n",
    "#\n",
    "# Modal verbs (e.g., \"may\", \"will\", \"should\") are not explicitly targeted\n",
    "# here. While they were central to the obligation analysis in the Python\n",
    "# pipeline, STM is focused on thematic structure, and these terms are not\n",
    "# expected to drive topic differentiation in this context.\n",
    "\n",
    "\n",
    "custom_stopwords <- c(\n",
    "  # Core domain context (shared across nearly all documents)\n",
    "  \"ai\", \"artificial\", \"intelligence\",\n",
    "  \"model\", \"models\", \"system\", \"systems\",\n",
    "  \"gpt\", \"gemini\", \"llm\", \"llms\",\n",
    "  \n",
    "  # Reporting / document structure language\n",
    "  \"report\", \"section\", \"table\", \"figure\", \"appendix\",\n",
    "  \"content\", \"version\",\n",
    "  \n",
    "  # Company identifiers (branding, not thematic content)\n",
    "  \"anthropic\", \"openai\", \"google\", \"microsoft\", \"meta\", \"deepmind\",\n",
    "  \n",
    "  # Generic filler terms\n",
    "  \"also\", \"such\", \"use\", \"using\"\n",
    ")\n",
    "\n",
    "# Note:\n",
    "# Terms such as \"risk\", \"risks\", \"safety\", \"deployment\", \"evaluation\",\n",
    "# and \"data\" are intentionally retained despite their high frequency.\n",
    "#\n",
    "# These terms are conceptually central to Responsible AI discourse and\n",
    "# are expected to structure meaningful topic variation across documents.\n",
    "# Removing them would reduce the model’s ability to capture differences\n",
    "# in governance emphasis and technical focus.\n",
    "\n",
    "\n",
    "# Run preprocessing\n",
    "# This step applies the cleaning decisions above and converts the text\n",
    "# into a format suitable for STM.\n",
    "\n",
    "processed <- textProcessor(\n",
    "  documents         = texts,\n",
    "  metadata          = metadata,\n",
    "  lowercase         = TRUE,\n",
    "  removestopwords   = TRUE,\n",
    "  removenumbers     = TRUE,\n",
    "  removepunctuation = TRUE,\n",
    "  stem              = TRUE,\n",
    "  wordLengths       = c(3, Inf),\n",
    "  customstopwords   = custom_stopwords,\n",
    "  verbose           = FALSE\n",
    ")\n",
    "\n",
    "\n",
    "# Prepare documents for STM\n",
    "\n",
    "#prepDocuments performs two key functions:\n",
    "# - removes rare terms\n",
    "# - ensures alignment between documents, vocabulary, and metadata\n",
    "#\n",
    "# lower.thresh = 2 retains terms appearing in at least two documents.\n",
    "# This reduces noise while preserving shared structure.\n",
    "#\n",
    "# Note:\n",
    "# This threshold can affect smaller or more specialized documents.\n",
    "# If documents collapse or are dropped, lowering this threshold may be necessary.\n",
    "\n",
    "\n",
    "out <- prepDocuments(\n",
    "  processed$documents,\n",
    "  processed$vocab,\n",
    "  processed$meta,\n",
    "  lower.thresh = 2,\n",
    "  verbose = FALSE\n",
    ")\n",
    "\n",
    "docs  <- out$documents\n",
    "vocab <- out$vocab\n",
    "meta  <- out$meta\n",
    "\n",
    "\n",
    "# Diagnostics\n",
    "\n",
    "#\n",
    "# These checks confirm that preprocessing preserved enough signal\n",
    "# and did not overly reduce the corpus.\n",
    "\n",
    "cat(paste(\"Vocabulary size:\", length(vocab), \"terms\\n\"))\n",
    "cat(paste(\"Documents retained:\", length(docs), \"\\n\"))\n",
    "\n",
    "# Inspect distribution of document lengths after preprocessing.\n",
    "# Extremely short documents may indicate overly aggressive filtering\n",
    "# or documents that are structurally different from the rest of the corpus.\n",
    "\n",
    "doc_lengths <- sapply(docs, function(x) sum(x[2, ]))\n",
    "                      \n",
    "cat(\"\\nDocument length summary (post-processing):\\n\")\n",
    "print(summary(doc_lengths))"
   ]
  },
