   "source": [
    "# STEP 4: CHOOSE THE NUMBER OF TOPICS (K)\n",
    "#\n",
    "# This step evaluates different values of K (number of topics) using searchK().\n",
    "# The goal is not to find a single “correct” K, but to identify a value that\n",
    "# balances interpretability and statistical fit.\n",
    "#\n",
    "# searchK() returns several diagnostics:\n",
    "# - Semantic coherence: do the top words in a topic meaningfully co-occur?\n",
    "#   Higher values indicate more interpretable topics.\n",
    "# - Exclusivity: are top words unique to a topic rather than shared across topics?\n",
    "#   Higher values indicate clearer topic separation.\n",
    "# - Held-out likelihood: overall model fit to unseen data.\n",
    "#   Higher values indicate better predictive performance.\n",
    "# - Residuals: how much structure remains unexplained.\n",
    "#\n",
    "# In practical terms, coherence and exclusivity often trade off against each other.\n",
    "# The goal is to find a reasonable balance rather than maximize a single metric.\n",
    "\n",
    "# Set a random seed to ensure reproducibility.\n",
    "# STM and searchK involve stochastic processes, so results can vary across runs.\n",
    "# Fixing the seed ensures that model diagnostics and topic structures remain\n",
    "# consistent and can be replicated.\n",
    "#\n",
    "# # The specific value (42) is arbitrary. \n",
    "# (A nod to The Hitchhiker’s Guide to the Galaxy, any fixed number would serve the same purpose and works.)\n",
    "set.seed(42)\n",
    "\n",
    "k_search <- searchK(\n",
    "  documents  = docs,\n",
    "  vocab      = vocab,\n",
    "  K          = c(5, 7, 10, 12, 15, 20),\n",
    "  prevalence = ~ company + doc_type + year,\n",
    "  data       = meta,\n",
    "  verbose    = FALSE,\n",
    "  cores      = 1\n",
    ")\n",
    "\n",
    "# Save diagnostic plot for inspection\n",
    "pdf(file.path(OUTPUT_PATH, \"k_selection_plot.pdf\"))\n",
    "plot(k_search)\n",
    "dev.off()\n",
    "\n",
    "# Print diagnostics in a readable table\n",
    "cat(\"Diagnostic statistics by K:\\n\")\n",
    "\n",
    "k_table <- data.frame(\n",
    "  K           = unlist(k_search$results$K),\n",
    "  coherence   = round(unlist(k_search$results$semcoh), 3),\n",
    "  exclusivity = round(unlist(k_search$results$exclus), 3),\n",
    "  heldout     = round(unlist(k_search$results$heldout), 3),\n",
    "  residual    = round(unlist(k_search$results$residual), 3)\n",
    ")\n",
    "\n",
    "print(k_table)\n",
    "\n"
   ]
  },
