   "source": [
    "# Selection decision\n",
    "#\n",
    "# I select K based on:\n",
    "# - relatively high semantic coherence (topics are interpretable)\n",
    "# - relatively high exclusivity (topics are distinct)\n",
    "# - stable or improved held-out likelihood (model fit)\n",
    "#\n",
    "# Given the corpus size (~50–60 documents), overly large K may\n",
    "# produce fragmented or unstable topics.\n",
    "#\n",
    "# In this case, K = 5 yields the highest coherence but produces topics\n",
    "# that are too broad to capture meaningful variation in the corpus.\n",
    "# As K increases, exclusivity improves but coherence declines,\n",
    "# indicating increasing fragmentation.\n",
    "#\n",
    "# K = 7 provides the best balance:\n",
    "# - coherence remains relatively high\n",
    "# - held-out likelihood is highest among tested values\n",
    "# - exclusivity improves without substantial loss of interpretability\n",
    "#\n",
    "# Higher values of K (10 and above) offer only marginal gains in\n",
    "# exclusivity while reducing coherence, suggesting diminishing returns.\n",
    "#\n",
    "# Based on these trade-offs, I select:\n",
    "\n",
    "K_SELECTED <- 7\n",
    "\n",
    "cat(paste(\"\\nProceeding with K =\", K_SELECTED, \"\\n\"))"
   ]
  },
