   "source": [
    "# STEP 5: FIT THE STRUCTURAL TOPIC MODEL\n",
    "#\n",
    "# This step fits the STM using the selected number of topics (K).\n",
    "# The goal is to estimate:\n",
    "# - the latent topics present in the corpus\n",
    "# - how topic prevalence varies across documents\n",
    "#\n",
    "# The prevalence formula specifies document-level covariates:\n",
    "# ~ company + doc_type + s(year)\n",
    "#\n",
    "# This means:\n",
    "# - topic prevalence can vary by company (e.g., OpenAI vs Anthropic)\n",
    "# - topic prevalence can vary by document type (e.g., policy vs technical report)\n",
    "# - topic prevalence can vary over time, modeled as a smooth function of year\n",
    "#\n",
    "# The smooth term s(year) allows for non-linear temporal patterns rather\n",
    "# than assuming a strictly linear trend.\n",
    "#\n",
    "# The content covariate (~ company) allows the model to capture differences\n",
    "# in how topics are expressed across companies, even when the underlying\n",
    "# topic is similar.\n",
    "#\n",
    "# This is useful for distinguishing:\n",
    "# - what is being discussed (topic prevalence)\n",
    "# - how it is being discussed (topic content variation)\n",
    "#\n",
    "# Note:\n",
    "# The content model adds complexity. If interpretation becomes unstable,\n",
    "# this component can be removed in a simplified version.\n",
    "\n",
    "\n",
    "set.seed(42)\n",
    "\n",
    "stm_model <- stm(\n",
    "  documents   = docs,\n",
    "  vocab       = vocab,\n",
    "  K           = K_SELECTED,\n",
    "  prevalence  = ~ company + doc_type + s(year),\n",
    "  content     = ~ company,\n",
    "  data        = meta,\n",
    "  max.em.its  = 75,\n",
    "  init.type   = \"Spectral\",\n",
    "  verbose     = TRUE\n",
    ")\n",
    "\n",
    "cat(\"\\nSTM fitting complete.\\n\")"
   ]
  },
