    "# STEP 6: EXAMINE TOPIC WORDS AND ASSIGN LABELS\n",
    "#\n",
    "# This step moves from model estimation to interpretation.\n",
    "# The goal is to understand what each topic represents and assign\n",
    "# a meaningful, conceptually grounded label.\n",
    "#\n",
    "# labelTopics() returns several types of words:\n",
    "# - Highest probability: most frequent words in the topic\n",
    "# - FREX: words that are both frequent and exclusive (most useful)\n",
    "# - Lift / Score: alternative measures of distinctiveness\n",
    "#\n",
    "# FREX words are prioritized because they balance frequency and exclusivity,\n",
    "# making them the most reliable indicators of what distinguishes a topic.\n",
    "#\n",
    "\n",
    "topic_labels <- labelTopics(stm_model, n = 10)\n",
    "print(topic_labels)\n",
    "\n",
    "\n",
    "# Save the FREX words to a text file\n",
    "sink(file.path(OUTPUT_PATH, \"topic_words.txt\"))\n",
    "cat(\"TOP FREX WORDS PER TOPIC\\n\\n\")\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  cat(paste0(\"Topic \", k, \": \"))\n",
    "  cat(paste(topic_labels$frex[k, ], collapse = \", \"))\n",
    "  cat(\"\\n\")\n",
    "}\n",
    "\n",
    "sink()\n",
    "\n",
    "cat(\"Saved topic_words.txt\\n\")\n"
   ]
  },
