    "# Important:\n",
    "# Topic labeling is an interpretive step rather than a mechanical one.\n",
    "# Words are not read in isolation, but as clusters that reflect underlying\n",
    "# concepts within each topic.\n",
    "\n",
    "# Labels should be based on:\n",
    "# - clusters of related terms\n",
    "# - recurring concepts across words\n",
    "# - how the topic differs from others\n",
    "# - domain knowledge of Responsible AI discourse\n",
    "\n",
    "# Note:\n",
    "# Words are shown in stemmed form (e.g., \"organiz\", \"resili\").\n",
    "# These are interpreted as their full forms (e.g., \"organization\",\n",
    "# \"resilience\") during topic labeling.\n",
    "\n",
    "# Also, where needed, I will also refer back to the original documents\n",
    "# to confirm interpretation rather than relying on word lists alone.\n",
    "\n",
    "# THOUGHT PROCESS FOLLOWED:\n",
    "# Labels should:\n",
    "# - reflect the underlying concept, not just keywords\n",
    "# - be concise but descriptive\n",
    "# - distinguish clearly from other topics\n",
    "# Avoid:\n",
    "# - generic labels (e.g., \"AI discussion\")\n",
    "# - repeating the same concept across multiple topics\n",
    "#\n",
    "# These labels will be used in figures and interpretation.\n",
    "\n",
    "topic_names <- c(\n",
    "  \"Governance Frameworks and Organizational Responsibility\",\n",
    "  \"Frontier Risk and Post-Deployment Mitigation\",\n",
    "  \"User Interaction, Prompting, and Content Intervention\",\n",
    "  \"Model Safety Systems and Risk Controls\",\n",
    "  \"Training, Evaluation, and Model Behavior\",\n",
    "  \"Communication, Transparency, and Stakeholder Engagement\",\n",
    "  \"Regulation, Policy Coordination, and Institutional Oversight\"\n",
    ")"
   ]
