   "source": [
    "# STEP 7: EXTRACT AND SAVE TOPIC PROPORTIONS\n",
    "#\n",
    "# This step extracts document-level topic proportions (theta),\n",
    "# where each value theta[i, k] represents the proportion of\n",
    "# document i associated with topic k.\n",
    "#\n",
    "# These proportions are used as inputs for downstream analysis\n",
    "# (e.g., regression models in the Python pipeline for RQ2 and RQ3).\n",
    "#\n",
    "# This creates a bridge between:\n",
    "# - STM (unsupervised topic discovery in R)\n",
    "# - statistical modeling (regression analysis in Python).\n",
    "\n",
    "theta <- stm_model$theta\n",
    "\n",
    "# Convert to data frame and assign readable column names\n",
    "topic_props <- as.data.frame(theta)\n",
    "colnames(topic_props) <- paste0(\"topic_\", 1:K_SELECTED, \"_prop\")\n",
    "\n",
    "# Attach document metadata\n",
    "#\n",
    "# Important:\n",
    "# The row order in theta matches the order of documents in 'meta'\n",
    "# after preprocessing. We therefore construct doc_id based on row position.\n",
    "\n",
    "topic_props$doc_id   <- seq_len(nrow(meta)) - 1\n",
    "topic_props$filename <- meta$filename\n",
    "topic_props$company  <- meta$company\n",
    "topic_props$year     <- meta$year\n",
    "topic_props$doc_type <- meta$doc_type\n",
    "\n",
    "# Save for use in Python\n",
    "write_csv(topic_props, file.path(OUTPUT_PATH, \"stm_topic_proportions.csv\"))\n",
    "\n",
    "cat(\"Saved stm_topic_proportions.csv\\n\")\n",
    "cat(\"This file will be used in Python to incorporate topic structure\\n\")\n",
    "cat(\"into regression models for RQ2 and RQ3.\\n\")"
   ]
  },
