    "# STEP 8: ESTIMATE COVARIATE EFFECTS ON TOPIC PREVALENCE\n",
    "#\n",
    "# This step examines how document-level covariates are associated with\n",
    "# variation in topic prevalence.\n",
    "#\n",
    "# estimateEffect() models how the proportion of each topic in a document\n",
    "# varies as a function of:\n",
    "# - company\n",
    "# - document type\n",
    "# - year (modeled as a smooth function)\n",
    "#\n",
    "# Importantly, this is not causal inference. The results indicate\n",
    "# systematic associations between covariates and topic prevalence,\n",
    "# holding other variables in the model constant.\n",
    "#\n",
    "# This provides the core quantitative link between:\n",
    "# - discovered topics (RQ1)\n",
    "# - organizational and document-level differences in discourse.\n",
    "\n",
    "cat(\"Estimating covariate effects. This takes a few minutes.\\n\")\n",
    "\n",
    "effect_company <- estimateEffect(\n",
    "  1:K_SELECTED ~ company,\n",
    "  stm_model,\n",
    "  meta,\n",
    "  uncertainty = \"Global\",\n",
    "  nsims = 250\n",
    ")\n",
    "\n",
    "effect_doctype <- estimateEffect(\n",
    "  1:K_SELECTED ~ doc_type,\n",
    "  stm_model,\n",
    "  meta,\n",
    "  uncertainty = \"Global\",\n",
    "  nsims = 250\n",
    ")\n",
    "\n",
    "effect_year <- estimateEffect(\n",
    "  1:K_SELECTED ~ s(year),\n",
    "  stm_model,\n",
    "  meta,\n",
    "  uncertainty = \"Global\",\n",
    "  nsims = 250\n",
    ")\n",
    "\n",
    "cat(\"Effects estimated.\\n\")\n",
    "\n",
    "# Summary provides coefficient estimates for each topic\n",
    "cat(\"\\nCompany effects summary:\\n\")\n",
    "summary(effect_company)"
   ]
  },
