    "# Plot topic prevalence by company\n",
    "\n",
    "plot(effect_company,\n",
    "     covariate = \"company\",\n",
    "     method    = \"difference\",\n",
    "     cov.value1 = \"OpenAI\",\n",
    "     cov.value2 = \"Anthropic\",\n",
    "     xlab      = \"Difference in topic prevalence\",\n",
    "     main      = \"Topic differences: OpenAI vs Anthropic\")"
   ]
