   "source": [
    "# Just out of Curiosity\n",
    "# OpenAI vs Google\n",
    "plot(effect_company,\n",
    "     covariate = \"company\",\n",
    "     method    = \"difference\",\n",
    "     cov.value1 = \"OpenAI\",\n",
    "     cov.value2 = \"GoogleDeepMind\")\n",
    "\n",
    "# Meta vs Microsoft\n",
    "plot(effect_company,\n",
    "     covariate = \"company\",\n",
    "     method    = \"difference\",\n",
    "     cov.value1 = \"Meta\",\n",
    "     cov.value2 = \"Microsoft\")"
