   "source": [
    "# STEP 9: FIND THE MOST REPRESENTATIVE DOCUMENT FOR EACH TOPIC\n",
    "#\n",
    "# This step identifies the document with the highest proportion for each topic.\n",
    "# In other words, it finds the document where a given topic is most dominant.\n",
    "#\n",
    "# The purpose is interpretive validation:\n",
    "# - to confirm that topic labels align with actual document content\n",
    "# - to move beyond word lists and examine full textual context\n",
    "# - to identify concrete examples that can be cited when describing topics\n",
    "#\n",
    "# Important:\n",
    "# Topic words provide signals, but representative documents provide meaning.\n",
    "# If the document does not match the assigned label, the label should be revised.\n",
    "#\n",
    "# This step also helps avoid over-interpreting noisy or ambiguous word clusters.\n",
    "\n",
    "sink(file.path(OUTPUT_PATH, \"representative_documents.txt\"))\n",
    "cat(\"MOST REPRESENTATIVE DOCUMENT PER TOPIC\\n\\n\")\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "\n",
    "  # Identify the document where topic k is most dominant\n",
    "  top_idx  <- which.max(theta[, k])\n",
    "  top_meta <- meta[top_idx, ]\n",
    "\n",
    "  cat(paste0(\"\\nTopic \", k, \" — \", topic_names[k], \"\\n\"))\n",
    "  cat(paste0(\"  File:        \", top_meta$filename, \"\\n\"))\n",
    "  cat(paste0(\"  Company:     \", top_meta$company,  \"\\n\"))\n",
    "  cat(paste0(\"  Year:        \", top_meta$year,     \"\\n\"))\n",
    "  cat(paste0(\"  Type:        \", top_meta$doc_type, \"\\n\"))\n",
    "  cat(paste0(\"  Proportion:  \", round(theta[top_idx, k], 3), \"\\n\"))\n",
    "\n",
    "  # Include FREX words for quick reference\n",
    "  cat(paste0(\"  FREX words:  \",\n",
    "             paste(topic_labels$frex[k, 1:8], collapse = \", \"), \"\\n\"))\n",
    "}\n",
    "\n",
    "sink()\n",
    "\n",
    "cat(\"Saved representative_documents.txt\\n\")\n",
    "\n"
   ]
  },
