   "source": [
    "# STEP 10: GENERATE RQ1 FIGURES (FINAL, PUBLICATION-READY)\n",
    "#\n",
    "# This step translates STM outputs into interpretable visual evidence.\n",
    "# While STM identifies latent topics, these figures show how those topics\n",
    "# are distributed across:\n",
    "#   - the full corpus\n",
    "#   - companies\n",
    "#   - document types\n",
    "#   - time\n",
    "#\n",
    "# This is where the analysis moves from discovery (topics) to explanation\n",
    "# (how discourse varies systematically across contexts).\n",
    "\n",
    "# PREP: STRUCTURE DATA FOR PLOTTING\n",
    "\n",
    "# theta contains topic proportions for each document\n",
    "theta_df <- as.data.frame(theta)\n",
    "colnames(theta_df) <- paste0(\"T\", 1:K_SELECTED)\n",
    "\n",
    "# Attach metadata so I can group and compare\n",
    "theta_df$company  <- meta$company\n",
    "theta_df$doc_type <- meta$doc_type\n",
    "theta_df$year     <- meta$year\n",
    "\n",
    "\n",
    "# Create lookup table with the topic names\n",
    "topic_lookup <- data.frame(\n",
    "  topic = paste0(\"T\", 1:K_SELECTED),\n",
    "  label = topic_names\n",
    ")\n",
    "\n",
    "# Define consistent company colors (same as Python plots)\n",
    "company_colors <- c(\n",
    "  \"Anthropic\" = \"#2c7bb6\",\n",
    "  \"OpenAI\" = \"#d7191c\",\n",
    "  \"GoogleDeepMind\" = \"#1a9641\",\n",
    "  \"Microsoft\" = \"#762a83\",\n",
    "  \"Meta\" = \"#e66101\"\n",
    ")\n",
    "\n",
    "\n",
    "# FIGURE 6: OVERALL TOPIC PREVALENCE\n",
    "\n",
    "# Shows which topics dominate the corpus overall.\n",
    "# This gives a high-level view of what Responsible AI discourse focuses on.\n",
    "# Figures are saved in both PNG and PDF formats.\n",
    "# PNG is used for quick inspection and presentation,\n",
    "# while PDF preserves vector quality for publication.\n",
    "\n",
    "topic_means <- colMeans(theta)\n",
    "\n",
    "topic_df <- data.frame(\n",
    "  topic = paste0(\"T\", 1:K_SELECTED),\n",
    "  mean_prop = topic_means\n",
    ") |>\n",
    "  left_join(topic_lookup, by = \"topic\") %>%\n",
    "  arrange(desc(mean_prop))\n",
    "\n",
    "\n",
    "p6 <- ggplot(topic_df, aes(x = reorder(label, mean_prop), y = mean_prop)) +\n",
    "  geom_col(fill = \"#2c7bb6\", alpha = 0.85, width = 0.7) +\n",
    "  coord_flip() +\n",
    "  scale_y_continuous(labels = percent_format()) +\n",
    "  labs(\n",
    "    title = \"Overall Topic Prevalence in Responsible AI Documents\",\n",
    "    x = \"Topic\",\n",
    "    y = \"Mean Proportion Across Documents\"\n",
    "  ) +\n",
    "  theme_minimal(base_size = 12) +\n",
    "  theme(\n",
    "    panel.grid.major.y = element_blank(),\n",
    "    plot.title = element_text(face = \"bold\")\n",
    "  )\n",
    "\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig6_topic_prevalence.png\"),\n",
    "       p6, width = 9, height = 6, dpi = 300)\n",
    "\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig6_topic_prevalence.pdf\"),\n",
    "       p6, width = 9, height = 6)\n",
    "\n",
    "cat(\"Saved fig6\\n\")\n",
    "\n",
    "\n",
    "# FIGURE 7: TOPIC PREVALENCE BY COMPANY\n",
    "#\n",
    "# Shows how companies differ in emphasis across topics.\n",
    "# Faceting avoids overcrowding and improves interpretability.\n",
    "\n",
    "co_topic <- theta_df %>%\n",
    "  group_by(company) %>%\n",
    "  summarise(across(starts_with(\"T\"), mean), .groups = \"drop\") %>%\n",
    "  pivot_longer(starts_with(\"T\"),\n",
    "               names_to = \"topic\",\n",
    "               values_to = \"mean_prop\") %>%\n",
    "  left_join(topic_lookup, by = \"topic\")\n",
    "\n",
    "p7 <- ggplot(co_topic, aes(x = company, y = mean_prop, fill = company)) +\n",
    "  geom_col(alpha = 0.9) +\n",
    "  facet_wrap(~ label, scales = \"free_y\") +\n",
    "  scale_fill_manual(values = company_colors) +\n",
    "  scale_y_continuous(labels = percent_format()) +\n",
    "  labs(\n",
    "    title = \"Topic Prevalence by Company\",\n",
    "    x = \"Company\",\n",
    "    y = \"Mean Topic Proportion\"\n",
    "  ) +\n",
    "  theme_minimal(base_size = 11) +\n",
    "  theme(\n",
    "    legend.position = \"none\",\n",
    "    strip.text = element_text(face = \"bold\"),\n",
    "    axis.text.x = element_text(angle = 30, hjust = 1),\n",
    "    plot.title = element_text(face = \"bold\")\n",
    "  )\n",
    "\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig7_topics_by_company.png\"),\n",
    "       p7, width = 12, height = 7, dpi = 300)\n",
    "\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig7_topics_by_company.pdf\"),\n",
    "       p7, width = 12, height = 7)\n",
    "\n",
    "\n",
    "# FIGURE 8: TOPIC PREVALENCE BY DOCUMENT TYPE\n",
    "#\n",
    "# Shows how different document genres (system cards, policies, reports)\n",
    "# structure discourse differently.\n",
    "\n",
    "dt_topic <- theta_df %>%\n",
    "  group_by(doc_type) %>%\n",
    "  summarise(across(starts_with(\"T\"), mean), .groups = \"drop\") %>%\n",
    "  pivot_longer(starts_with(\"T\"),\n",
    "               names_to = \"topic\",\n",
    "               values_to = \"mean_prop\") %>%\n",
    "  left_join(topic_lookup, by = \"topic\")\n",
    "\n",
    "p8 <- ggplot(dt_topic, aes(x = doc_type, y = mean_prop, fill = doc_type)) +\n",
    "  geom_col(alpha = 0.9) +\n",
    "  facet_wrap(~ label, scales = \"free_y\") +\n",
    "  scale_fill_manual(\n",
    "  values = colorRampPalette(brewer.pal(8, \"Set2\"))(length(unique(dt_topic$doc_type)))\n",
    ") +\n",
    "  scale_y_continuous(labels = percent_format()) +\n",
    "  labs(\n",
    "    title = \"Topic Prevalence by Document Type\",\n",
    "    x = \"Document Type\",\n",
    "    y = \"Mean Topic Proportion\"\n",
    "  ) +\n",
    "  theme_minimal(base_size = 11) +\n",
    "  theme(\n",
    "    legend.position = \"none\",\n",
    "    strip.text = element_text(face = \"bold\"),\n",
    "    axis.text.x = element_text(angle = 30, hjust = 1),\n",
    "    plot.title = element_text(face = \"bold\")\n",
    "  )\n",
    "\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig8_topics_by_doctype.png\"),\n",
    "       p8, width = 12, height = 7, dpi = 300)\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig8_topics_by_doctype.pdf\"),\n",
    "       p8, width = 12, height = 7)\n",
    "\n",
    "\n",
    "# FIGURE 9: TOPIC TRENDS OVER TIME\n",
    "#\n",
    "# Shows how discourse shifts across years.\n",
    "# This helps identify emerging vs declining themes.\n",
    "\n",
    "yr_topic <- theta_df %>%\n",
    "  group_by(year) %>%\n",
    "  summarise(across(starts_with(\"T\"), mean), .groups = \"drop\") %>%\n",
    "  pivot_longer(starts_with(\"T\"),\n",
    "               names_to = \"topic\",\n",
    "               values_to = \"mean_prop\") %>%\n",
    "  left_join(topic_lookup, by = \"topic\")\n",
    "\n",
    "p9 <- ggplot(yr_topic, aes(x = year, y = mean_prop, group = label)) +\n",
    "  geom_line(color = \"#2c7bb6\", linewidth = 1) +\n",
    "  geom_point(color = \"#2c7bb6\", size = 2) +\n",
    "  facet_wrap(~ label, scales = \"free_y\") +\n",
    "  scale_y_continuous(labels = percent_format()) +\n",
    "  scale_x_continuous(breaks = c(2022, 2023, 2024, 2025)) +\n",
    "  labs(\n",
    "    title = \"Topic Trends Over Time\",\n",
    "    x = \"Year\",\n",
    "    y = \"Mean Topic Proportion\"\n",
    "  ) +\n",
    "  theme_minimal(base_size = 11) +\n",
    "  theme(\n",
    "    strip.text = element_text(face = \"bold\"),\n",
    "    plot.title = element_text(face = \"bold\")\n",
    "  )\n",
    "\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig9_topics_over_time.png\"),\n",
    "       p9, width = 12, height = 7, dpi = 300)\n",
    "ggsave(file.path(OUTPUT_PATH, \"fig9_topics_over_time.pdf\"),\n",
    "       p9, width = 12, height = 7)\n",
    "\n",
    "# FIGURE 10: WORD CLOUDS (APPENDIX)\n",
    "#\n",
    "# These are exploratory and mainly useful for inspection.\n",
    "\n",
    "pdf(file.path(OUTPUT_PATH, \"fig10_topic_wordclouds.pdf\"),\n",
    "    width = 16, height = 12)\n",
    "png(file.path(OUTPUT_PATH, \"fig10_topics_wordclouds.png\"),\n",
    "    width = 1400, height = 1000, res = 150)\n",
    "\n",
    "par(mfrow = c(ceiling(K_SELECTED / 3), 3), mar = c(1, 1, 3, 1))\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  cloud(\n",
    "    stm_model,\n",
    "    topic = k,\n",
    "    scale = c(3, 0.5),\n",
    "    max.words = 20,\n",
    "    main = topic_names[k]\n",
    "  )\n",
    "}\n",
    "\n",
    "# Save to PDF\n",
    "pdf(file.path(OUTPUT_PATH, \"fig10_topic_wordclouds.pdf\"),\n",
    "    width = 16, height = 12)\n",
    "\n",
    "par(mfrow = c(ceiling(K_SELECTED / 3), 3), mar = c(1, 1, 3, 1))\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  cloud(stm_model, topic = k, scale = c(3, 0.5), max.words = 20, main = topic_names[k])\n",
    "}\n",
    "\n",
    "dev.off()\n",
    "\n",
    "\n",
    "# Save to PNG\n",
    "png(file.path(OUTPUT_PATH, \"fig10_topic_wordclouds.png\"),\n",
    "    width = 1400, height = 1000, res = 150)\n",
    "\n",
    "par(mfrow = c(ceiling(K_SELECTED / 3), 3), mar = c(1, 1, 3, 1))\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  cloud(stm_model, topic = k, scale = c(3, 0.5), max.words = 20, main = topic_names[k])\n",
    "}\n",
    "\n",
    "dev.off()\n",
    "\n",
    "# Show in notebook\n",
    "par(mfrow = c(ceiling(K_SELECTED / 3), 3), mar = c(1, 1, 3, 1))\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  cloud(stm_model, topic = k, scale = c(3, 0.5), max.words = 20, main = topic_names[k])\n",
    "}\n",
    "\n",
    "\n",
    "# FIGURE 11: COMPANY EFFECTS\n",
    "#\n",
    "# Shows how topic prevalence differs across companies,\n",
    "# controlling for other variables in the STM.\n",
    "\n",
    "pdf(file.path(OUTPUT_PATH, \"fig11_company_effects.pdf\"),\n",
    "    width = 14, height = 10)\n",
    "png(file.path(OUTPUT_PATH, \"fig11_company_effects.png\"),\n",
    "    width = 1400, height = 1000, res = 150)\n",
    "\n",
    "# Adjust spacing for readability\n",
    "par(\n",
    "  mfrow = c(ceiling(K_SELECTED / 3), 3),\n",
    "  mar   = c(3, 4, 3, 1),   # margins (bottom, left, top, right)\n",
    "  oma   = c(2, 2, 2, 1)    # outer margins\n",
    ")\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "\n",
    "  plot(effect_company,\n",
    "       covariate = \"company\",\n",
    "       topics    = k,\n",
    "       model     = stm_model,\n",
    "       method    = \"pointestimate\",\n",
    "       main      = topic_names[k],\n",
    "       xlab      = \"Expected Topic Proportion\",\n",
    "       labeltype = \"custom\",\n",
    "       custom.labels = levels(factor(meta$company)),\n",
    "       cex.main  = 0.9,\n",
    "       cex.axis  = 0.8,\n",
    "       cex.lab   = 0.9)\n",
    "}\n",
    "\n",
    "dev.off()\n",
    "\n",
    "# To show\n",
    "par(\n",
    "  mfrow = c(ceiling(K_SELECTED / 3), 3),\n",
    "  mar   = c(3, 4, 3, 1)\n",
    ")\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  plot(effect_company,\n",
    "       covariate = \"company\",\n",
    "       topics    = k,\n",
    "       model     = stm_model,\n",
    "       method    = \"pointestimate\",\n",
    "       main      = topic_names[k],\n",
    "       xlab      = \"Expected Topic Proportion\",\n",
    "       labeltype = \"custom\",\n",
    "       custom.labels = levels(factor(meta$company)),\n",
    "       cex.main  = 0.9,\n",
    "       cex.axis  = 0.8,\n",
    "       cex.lab   = 0.9)\n",
    "}\n",
    "\n",
    "\n",
    "# FIGURE 12: DOCUMENT TYPE EFFECTS\n",
    "\n",
    "# Shows how discourse differs by genre (policy vs technical vs reports).\n",
    "\n",
    "pdf(file.path(OUTPUT_PATH, \"fig12_doctype_effects.pdf\"),\n",
    "    width = 14, height = 10)\n",
    "png(file.path(OUTPUT_PATH, \"fig12_doctype_effects.png\"),\n",
    "    width = 1400, height = 1000, res = 150)\n",
    "\n",
    "par(mfrow = c(ceiling(K_SELECTED / 3), 3))\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  plot(effect_doctype,\n",
    "       covariate = \"doc_type\",\n",
    "       topics = k,\n",
    "       model = stm_model,\n",
    "       method = \"pointestimate\",\n",
    "       main = paste0(topic_names[k], \" by Document Type\"),\n",
    "       xlab = \"Expected Topic Proportion\",\n",
    "       cex.main = 0.9)\n",
    "}\n",
    "\n",
    "dev.off()\n",
    "\n",
    "#To show\n",
    "par(\n",
    "  mfrow = c(ceiling(K_SELECTED / 3), 3),\n",
    "  mar   = c(3, 4, 3, 1)\n",
    ")\n",
    "\n",
    "for (k in 1:K_SELECTED) {\n",
    "  plot(effect_doctype,\n",
    "       covariate = \"doc_type\",\n",
    "       topics    = k,\n",
    "       model     = stm_model,\n",
    "       method    = \"pointestimate\",\n",
    "       main      = topic_names[k],\n",
    "       xlab      = \"Expected Topic Proportion\",\n",
    "       labeltype = \"custom\",\n",
    "       custom.labels = levels(factor(meta$doc_type)),\n",
    "       cex.main  = 0.9,\n",
    "       cex.axis  = 0.8,\n",
    "       cex.lab   = 0.9)\n",
    "}\n",
    "\n",
    "\n",
    "cat(\"All RQ1 figures saved successfully.\\n\")\n"
   ]
