   "source": [
    "# STEP 11: TOPIC CORRELATION NETWORK\n",
    "#\n",
    "# This step examines how topics co-occur within documents.\n",
    "# topicCorr() estimates correlations between topic proportions.\n",
    "#\n",
    "# Interpretation:\n",
    "# - Positive correlation → topics tend to appear together\n",
    "# - Negative correlation → topics tend to avoid each other\n",
    "#\n",
    "# This helps identify:\n",
    "# - clusters of related discourse\n",
    "# - whether themes are modular or interconnected\n",
    "\n",
    "\n",
    "# Compute topic correlations\n",
    "topic_corr <- topicCorr(stm_model)\n",
    "\n",
    "\n",
    "# SAVE TO PDF\n",
    "pdf(file.path(OUTPUT_PATH, \"fig13_topic_correlations.pdf\"),\n",
